
  CREATE TABLE MELANBIDE87_INSTALACIONES 
   (	ID NUMBER(8,0), 
	NUM_EXP VARCHAR2(20 BYTE), 
	TIPINST VARCHAR2(1 BYTE), 
	INSTMUNICIPIO VARCHAR2(150 BYTE), 
	INSTLOCALIDAD VARCHAR2(150 BYTE), 
	INSTDIRECCION VARCHAR2(200 BYTE), 	
	INSTCP NUMBER(5,0)
   );

   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.ID IS 'Identificador Secuencial';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.NUM_EXP IS 'Número de Expediente';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.TIPINST IS 'Tipo de Instalación';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.INSTMUNICIPIO IS 'Municipio de la Instalación';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.INSTLOCALIDAD IS 'Localidad de la Instalación';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.INSTDIRECCION IS 'Dirección de la Instalación';
   COMMENT ON COLUMN MELANBIDE87_INSTALACIONES.INSTCP IS 'Código Postal de la Instalación';

--------------------------------------------------------
--  Constraints for Table MELANBIDE87_INSTALACIONES
--------------------------------------------------------
  ALTER TABLE MELANBIDE87_INSTALACIONES ADD PRIMARY KEY (ID);
  
--------------------------------------------------------
--  DDL for Sequence SEQ_MELANBIDE87_INSTALACIONES
--------------------------------------------------------

   CREATE SEQUENCE  SEQ_MELANBIDE87_INSTALACIONES  MINVALUE 0 MAXVALUE 99999999 INCREMENT BY 1 START WITH 1 NOCACHE  NOORDER  NOCYCLE ;
  

